  show_gift_action = EXCLUDED.show_gift_action,
  gift_friendly = EXCLUDED.gift_friendly,
  buyer_mode_label = EXCLUDED.buyer_mode_label,
  gift_note = EXCLUDED.gift_note,
  ownership_note = EXCLUDED.ownership_note,
  product_family_label = EXCLUDED.product_family_label,
  primary_persona = EXCLUDED.primary_persona,
  card_cta_label = EXCLUDED.card_cta_label,
  render_rule = EXCLUDED.render_rule,
  is_active = true,
  updated_at = now();

UPDATE public.pl_age_band_category_type_products p
SET
  is_active = false,
  updated_at = now()
WHERE p.age_band_id IN (SELECT DISTINCT age_band_id FROM tmp_discover_projection_stage);

DO $$
DECLARE
  v_rows_loaded INTEGER;
  v_rows_16_18m INTEGER;
  v_clusters_16_18m INTEGER;
  v_rows_22_24m INTEGER;
  v_clusters_22_24m INTEGER;
  v_rows_28_30m INTEGER;
  v_clusters_28_30m INTEGER;
  v_rows_34_36m INTEGER;
  v_clusters_34_36m INTEGER;
  v_stage3_active INTEGER;
BEGIN
  SELECT COUNT(*) INTO v_rows_loaded FROM tmp_discover_projection_stage;
  SELECT COUNT(*) INTO v_rows_16_18m FROM tmp_discover_projection_stage WHERE age_band_id = '16-18m';
  SELECT COUNT(DISTINCT stage1_wrapper_ux_slug) INTO v_clusters_16_18m
  FROM tmp_discover_projection_stage WHERE age_band_id = '16-18m';
  SELECT COUNT(*) INTO v_rows_22_24m FROM tmp_discover_projection_stage WHERE age_band_id = '22-24m';
  SELECT COUNT(DISTINCT stage1_wrapper_ux_slug) INTO v_clusters_22_24m
  FROM tmp_discover_projection_stage WHERE age_band_id = '22-24m';
  SELECT COUNT(*) INTO v_rows_28_30m FROM tmp_discover_projection_stage WHERE age_band_id = '28-30m';
  SELECT COUNT(DISTINCT stage1_wrapper_ux_slug) INTO v_clusters_28_30m
  FROM tmp_discover_projection_stage WHERE age_band_id = '28-30m';
  SELECT COUNT(*) INTO v_rows_34_36m FROM tmp_discover_projection_stage WHERE age_band_id = '34-36m';
  SELECT COUNT(DISTINCT stage1_wrapper_ux_slug) INTO v_clusters_34_36m
  FROM tmp_discover_projection_stage WHERE age_band_id = '34-36m';
  SELECT COUNT(*) INTO v_stage3_active
  FROM public.pl_age_band_category_type_products
  WHERE age_band_id IN ('16-18m', '22-24m', '28-30m', '34-36m')
    AND is_active = true;

  RAISE NOTICE 'Discover projection rows loaded: % (expected 189)', v_rows_loaded;
  RAISE NOTICE '16-18m rows: % (expected 33), clusters: % (expected 8)', v_rows_16_18m, v_clusters_16_18m;
  RAISE NOTICE '22-24m rows: % (expected 59), clusters: % (expected 8)', v_rows_22_24m, v_clusters_22_24m;
  RAISE NOTICE '28-30m rows: % (expected 47), clusters: % (expected 8)', v_rows_28_30m, v_clusters_28_30m;
  RAISE NOTICE '34-36m rows: % (expected 50), clusters: % (expected 8)', v_rows_34_36m, v_clusters_34_36m;
  RAISE NOTICE 'Active Stage 3 mappings (expected 0): %', v_stage3_active;

  IF v_rows_loaded <> 189 THEN
    RAISE EXCEPTION 'Row count validation failed';
  END IF;
  IF v_rows_16_18m <> 33 THEN
    RAISE EXCEPTION 'Row count validation failed for 16-18m';
  END IF;
  IF v_rows_22_24m <> 59 THEN
    RAISE EXCEPTION 'Row count validation failed for 22-24m';
  END IF;
  IF v_rows_28_30m <> 47 THEN
    RAISE EXCEPTION 'Row count validation failed for 28-30m';
  END IF;
  IF v_rows_34_36m <> 50 THEN
    RAISE EXCEPTION 'Row count validation failed for 34-36m';
  END IF;
  IF v_clusters_16_18m <> 8 THEN
    RAISE EXCEPTION 'Cluster count validation failed for 16-18m';
  END IF;
  IF v_clusters_22_24m <> 8 THEN
    RAISE EXCEPTION 'Cluster count validation failed for 22-24m';
  END IF;
  IF v_clusters_28_30m <> 8 THEN
    RAISE EXCEPTION 'Cluster count validation failed for 28-30m';
  END IF;
  IF v_clusters_34_36m <> 8 THEN
    RAISE EXCEPTION 'Cluster count validation failed for 34-36m';
  END IF;
END $$;

